def mode(nums):
    if not nums:
        return None
    counts = {}
    for num in nums:
        counts[num] = counts.get(num, 0) + 1
    max_count, result = max(counts.items(), key=lambda item: item[1])
    for k, v in counts.items():
        if v == max_count and k < result:
            result = k
    return result
